using sv_0e0118fb21c6484ba4d29e3b46d79866.Services;
using Microsoft.AspNetCore.Components;

namespace sv_0e0118fb21c6484ba4d29e3b46d79866.Components.Pages;

public partial class Settings : ComponentBase
{
    private string ActiveSection { get; set; } = "Profile";

    // Toast
    private string? ToastMessage { get; set; }
    private string ToastType { get; set; } = "toast-success";

    // Profile
    private UserProfile? _profile;
    private EditableProfile _editProfile = new();

    // Notifications
    private NotificationPrefs? _notifPrefs;
    private EditableNotif _editNotif = new();
    private Dictionary<string, bool> _mutedState = new();

    // Security
    private SecuritySettings? _security;
    private bool ShowPasswordPanel { get; set; }
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool ShowRevokeConfirm { get; set; }
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private AppearanceSettings? _appearance;
    private EditableAppearance _editAppearance = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
        await LoadNotifications();
        await LoadSecurity();
        await LoadAppearance();
    }

    private void SetSection(string section)
    {
        ActiveSection = section;
    }

    // Profile methods
    private async Task LoadProfile()
    {
        _profile = await SettingsService.GetProfileAsync();
        _editProfile = new EditableProfile
        {
            DisplayName = _profile.DisplayName,
            Email = _profile.Email,
            AvatarUrl = _profile.AvatarUrl,
            Bio = _profile.Bio
        };
    }

    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editProfile.DisplayName, _editProfile.Email, _editProfile.AvatarUrl, _editProfile.Bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        ShowToast("Profile saved successfully!", "toast-success");
    }

    private void DiscardProfileChanges()
    {
        if (_profile != null)
        {
            _editProfile = new EditableProfile
            {
                DisplayName = _profile.DisplayName,
                Email = _profile.Email,
                AvatarUrl = _profile.AvatarUrl,
                Bio = _profile.Bio
            };
        }
    }

    // Notifications methods
    private async Task LoadNotifications()
    {
        _notifPrefs = await SettingsService.GetNotificationPrefsAsync();
        _editNotif = new EditableNotif
        {
            EmailNotifications = _notifPrefs.EmailNotifications,
            PushNotifications = _notifPrefs.PushNotifications,
            WeeklyDigest = _notifPrefs.WeeklyDigest,
            MutedChannels = new List<string>(_notifPrefs.MutedChannels)
        };
        _mutedState = _notifPrefs.MutedChannels.ToDictionary(c => c, _ => true);
    }

    private void ToggleMute(string channel, bool muted)
    {
        _mutedState[channel] = muted;
    }

    private async Task SaveNotifications()
    {
        var mutedChannels = _mutedState.Where(kv => kv.Value).Select(kv => kv.Key).ToList();
        var prefs = new NotificationPrefs(_editNotif.EmailNotifications, _editNotif.PushNotifications, _editNotif.WeeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notifPrefs = prefs;
        ShowToast("Notification preferences saved!", "toast-success");
    }

    // Security methods
    private async Task LoadSecurity()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private void TogglePasswordPanel()
    {
        ShowPasswordPanel = !ShowPasswordPanel;
    }

    private async Task UpdatePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", "toast-error");
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", "toast-error");
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        ShowPasswordPanel = false;
        await LoadSecurity();
        ShowToast("Password updated successfully!", "toast-success");
    }

    private void ConfirmRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        ShowRevokeConfirm = true;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
        ShowRevokeConfirm = false;
    }

    private async Task RevokeSession()
    {
        if (_sessionToRevoke != null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            await LoadSecurity();
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.", "toast-success");
        }
        ShowRevokeConfirm = false;
        _sessionToRevoke = null;
    }

    // Appearance methods
    private async Task LoadAppearance()
    {
        _appearance = await SettingsService.GetAppearanceAsync();
        _editAppearance = new EditableAppearance
        {
            Theme = _appearance.Theme,
            FontSize = _appearance.FontSize,
            Language = _appearance.Language,
            CompactMode = _appearance.CompactMode
        };
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_editAppearance.Theme, _editAppearance.FontSize, _editAppearance.Language, _editAppearance.CompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
        ShowToast("Appearance settings saved!", "toast-success");
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"preview-theme-{_editAppearance.Theme.ToLowerInvariant()}");
        classes.Add($"preview-font-{_editAppearance.FontSize.ToLowerInvariant()}");
        if (_editAppearance.CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    // Toast
    private void ShowToast(string message, string type)
    {
        ToastMessage = message;
        ToastType = type;
        _ = DismissToastAfterDelay();
    }

    private async Task DismissToastAfterDelay()
    {
        await Task.Delay(3000);
        ToastMessage = null;
        await InvokeAsync(StateHasChanged);
    }

    private void DismissToast()
    {
        ToastMessage = null;
    }

    // Editable models for two-way binding
    private class EditableProfile
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";
    }

    private class EditableNotif
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = new();
    }

    private class EditableAppearance
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "English";
        public bool CompactMode { get; set; }
    }
}

